    def _sort_palette(self, sort_palette):
        """
        Reorders a "P" mode image's palette without changing its appearance,
        remapping pixel values so that they still point at the same colors.

        :param sort_palette: ``"brightness"`` to sort colors from darkest to
           lightest, or ``"rgb"`` to sort colors by their (r, g, b) value.
        :returns: A new image with the palette reordered.
        """
        palette = self.im.getpalette("RGB")
        colors = [tuple(palette[i : i + 3]) for i in range(0, len(palette), 3)]

        if sort_palette == "brightness":
            def sort_key(i):
                r, g, b = colors[i]
                return r * 299 + g * 587 + b * 114

        elif sort_palette == "rgb":
            def sort_key(i):
                return colors[i]

        else:
            raise ValueError("sort_palette must be 'brightness' or 'rgb'")

        dest_map = sorted(range(len(colors)), key=sort_key)
        return self.remap_palette(dest_map)

